INSERT INTO `saved_recipes` VALUES (1,'Nigerian Jollof Rice','{\"name\": \"Nigerian Jollof Rice\", \"tips\": \"The secret to party jollof is double covering with foil and lid to trap steam, and finishing on high heat for the smoky bottom layer. Never use fresh tomatoes alone — always add tomato paste for depth of colour and flavour.\", \"servings\": 6, \"difficulty\": \"medium\", \"description\": \"Nigerian Jollof Rice is one of the most beloved dishes in West Africa, known for its rich smoky tomato flavour and vibrant orange-red colour. It is a staple at every Nigerian party, celebration, and family gathering. The secret to authentic Jollof Rice is the smoky bottom layer called party jollof which develops from cooking on high heat at the end.\", \"instructions\": [\"Step 1: Blend tomatoes, red bell peppers, long chilli peppers, scotch bonnet, and onions together in a blender until completely smooth with no chunks remaining. Set aside.\", \"Step 2: Wash rice thoroughly in cold water at least 3 times until water runs clear.\", \"Step 3: Heat vegetable oil in a large heavy-bottomed stainless steel or aluminum pot over medium-high heat for 2 minutes. Slice some onions, ginger and garlic paste, curry, thyme, bay leaves  and fry in the oil for 3 minutes.\", \"Step 4: Add tomato paste to the pot and fry with the mix for 3 minutes on medium heat, stirring constantly until the paste darkens slightly from bright red to a deeper reddish brown.\", \"Step 5: Pour the blended pepper mixture with some paprika into the pot. It will sizzle loudly — this is correct. Add in some seasoning cubes and salt. Fry on medium high heat uncovered for 25-30 minutes stirring every 5 minutes until all the water has evaporated, the oil floats on top, and the sauce has darkened to a deep red color. This step is critical — do not rush it.\", \"Step 6: Stir well and taste the sauce should be slightly salty as it will season the rice\", \"Step 7: Add the rice to the pot and stir well to coat every grain with the tomato sauce. Fry on high for like 2 minutes. Then add in chicken stock and some water enough to just cover the rice\", \"Step 8: Cover the pot tightly with foil first then place the lid on top to seal in all the steam. Cook on medium heat for 20 minutes without lifting the lid.\", \"Step 9: After 20 minutes lift the lid and check — rice should be almost fully cooked and liquid mostly absorbed. Stir gently from bottom to top. Cover again and cook on very low heat for 10 more minutes.\", \"Step 10: For the authentic party jollof smoky bottom, add in some cooking butter and sliced onions turn heat to high for the last 3-5 minutes. You will hear a crackling sound from the bottom — this is correct. Remove from heat immediately and leave covered for 5 minutes before serving.\"], \"match_percentage\": 12.5, \"used_ingredients\": [\"long grain parboiled rice\", \"tomato paste\"], \"cook_time_minutes\": 70, \"prep_time_minutes\": 20, \"missing_ingredients\": [\"tomatoes\", \"red bell peppers (tatashe)\", \"long chilli peppers(shombo) \", \"scotch bonnet peppers (ata rodo)\", \"onions\", \"vegetable oil\", \"chicken stock\", \"seasoning cubes\", \"curry powder\", \"thyme\", \"bay leaves\", \"garlic powder\", \"salt\", \"paprika\"]}','2026-06-21 09:50:24'),(2,'Moi Moi','{\"name\": \"Moi Moi\", \"tips\": \"The food processor peeling method is a game changer — it cuts prep time from 30 minutes to 5 minutes. The two most important steps are removing every single bean skin and whisking the paste vigorously to aerate it before adding seasoning. Skipping either step will result in dense heavy Moi Moi. Always fill containers only three quarters full as the paste expands during steaming.\", \"region\": \"yoruba\", \"category\": \"side_dish\", \"servings\": 8, \"difficulty\": \"medium\", \"description\": \"Moi Moi is a traditional Nigerian steamed bean pudding made from peeled beans blended into a smooth paste. It is a beloved dish across all Nigerian tribes and is served at parties, as a side dish with rice or ogi, or eaten alone as a complete meal. The texture should be firm yet soft and moist inside with a rich savoury flavour.\", \"ingredients\": [\"beans\", \"onions\", \"scotch bonnet peppers\", \"long chilli pepper (shombo)\", \"crayfish\", \"vegetable oil\", \"seasoning cubes\", \"salt\", \"eggs\", \"fish (preferably mackerel fish)\", \"water\"], \"instructions\": [\"Step 1: There are two ways to peel the beans. Traditional method: Pour beans into a bowl and soak in cold water for 30 minutes until the skins begin to loosen and soften, then rub vigorously between both palms under running water until all skins float off. Quick method: Pour dry beans into a food processor with some water and pulse for 30 to 45 seconds — the food processor will crack and loosen the skins without grinding the beans. Pour the pulsed beans into a large bowl of water, the skins will float to the top — skim them off and drain. Repeat until all skins are removed. The quick method takes 5 minutes instead of 30.\", \"Step 2: Rinse the peeled beans thoroughly in clean water two to three times to remove any remaining skin fragments. The beans should be completely white with no dark skin remaining — any leftover skin will make the Moi Moi rough and bitter.\", \"Step 3: Place the peeled beans directly into the blender together with the scotch bonnet peppers, red bell pepper, onions, one raw egg, and a very small amount of water — just enough to get the blender moving. Blend everything together on high speed for 3 minutes until the paste is completely smooth with absolutely no grainy texture. Blending the peppers and egg together with the beans at this stage gives the Moi Moi its full flavour and colour from the inside.\", \"Step 4: Pour the blended paste into a large bowl. Add seasoning cubes, vegetable oil, and salt. Mix everything together thoroughly until well combined. Taste and adjust seasoning — it should be well seasoned and slightly peppery.\", \"Step 5: Using a wooden spoon or electric hand mixer, whisk the paste vigorously for 5 minutes until it becomes fluffy, lighter in colour, and increases slightly in volume. This aerates the paste and gives Moi Moi its soft moist texture when steamed.\", \"Step 6: Break the mackerel fish into medium sized chunks and slice your boiled eggs and set aside. Grease foil containers or moi moi leaves generously with vegetable oil on the inside so the moi moi does not stick.\", \"Step 7: Pour the bean paste mixture into each container filling only three quarters full. Drop pieces of fish directly into the paste in each container alongside the sliced eggs  — the fish sits inside the moi moi not on top. Press down lightly so the fish is submerged in the paste.\", \"Step 8: Seal each foil container tightly by folding the edges over securely. No steam should be able to escape during cooking.\", \"Step 9: Place a trivet or folded foil at the bottom of a large pot to prevent direct heat contact. Arrange the sealed moi moi containers in the pot and add water to reach halfway up the sides of the containers.\", \"Step 10: Cover the pot tightly and steam on medium heat for 45 to 60 minutes. Check water level every 15 minutes and add more hot water if needed — never let the pot run dry. Moi Moi is ready when it feels firm when pressed gently and pulls away cleanly from the container when opened.\"], \"cook_time_minutes\": 60, \"prep_time_minutes\": 40}','2026-06-21 12:24:00');
