INSERT INTO `suggestion_requests` VALUES ('02126720-a147-40ef-881c-0d4d4f3f935f','[\"rice\", \"tomatoes\", \"tomato paste\", \"onions\", \"scotch bonnet\", \"chicken\", \"vegetable oil\", \"seasoning cubes\", \"bay leaves\", \"curry powder\"]','nigerian',60,'{\"recipes\": [{\"name\": \"Nigerian Jollof Rice\", \"servings\": 4, \"difficulty\": \"easy\", \"description\": \"A popular Nigerian one-pot dish made with rice, tomatoes, and spices, known for its flavorful and aromatic taste profile.\", \"instructions\": [\"Heat 2 tablespoons of vegetable oil in a large pot over medium heat for 2 minutes\", \"Add 1 large onion, chopped, and sauté for 5 minutes\", \"Add 2 large tomatoes, chopped, and 1 scotch bonnet pepper, chopped, to the pot and stir well to combine\", \"Add 2 cups of water to the pot and bring to a boil\", \"Add 1 cup of uncooked long-grain rice to the pot, stir well to combine, and reduce the heat to low\", \"Remove the pot from the heat and let it rest, covered, for 5 minutes\"], \"match_percentage\": 94, \"used_ingredients\": [\"rice\", \"tomatoes\", \"tomato paste\", \"onions\", \"scotch bonnet\", \"vegetable oil\", \"seasoning cubes\"], \"cook_time_minutes\": 40, \"prep_time_minutes\": 15, \"missing_ingredients\": [\"salt\"]}, {\"name\": \"Nigerian Fried Rice\", \"servings\": 4, \"difficulty\": \"easy\", \"description\": \"A Nigerian-style fried rice dish made with cooked rice, vegetables, and spices, known for its flavorful and savory taste profile.\", \"instructions\": [\"Heat 1 tablespoon of vegetable oil in a large skillet or wok over medium-high heat for 1 minute\", \"Add 1 large onion, chopped, and stir-fry for 2 minutes\", \"Add 1 large tomato, chopped, and 1 scotch bonnet pepper, chopped, to the skillet and stir-fry for 2 minutes\", \"Add 2 cups of cooked rice to the skillet and stir-fry for 5 minutes\", \"Remove the skillet from the heat and let it rest for 1 minute\"], \"match_percentage\": 86, \"used_ingredients\": [\"rice\", \"tomatoes\", \"onions\", \"scotch bonnet\", \"vegetable oil\", \"seasoning cubes\"], \"cook_time_minutes\": 20, \"prep_time_minutes\": 10, \"missing_ingredients\": [\"salt\", \"eggs\", \"plantains\"]}, {\"name\": \"Nigerian Chicken and Rice\", \"servings\": 4, \"difficulty\": \"medium\", \"description\": \"A hearty Nigerian dish made with chicken, rice, and spices, known for its flavorful and aromatic taste profile.\", \"instructions\": [\"Heat 2 tablespoons of vegetable oil in a large pot over medium heat for 2 minutes\", \"Add 1 large onion, chopped, and sauté for 5 minutes\", \"Add 1 pound of chicken, cut into bite-sized pieces, to the pot and cook for 5 minutes\", \"Add 1 cup of uncooked rice to the pot and stir well to combine\", \"Add 2 cups of water to the pot and bring to a boil\"], \"match_percentage\": 83, \"used_ingredients\": [\"chicken\", \"rice\", \"onions\", \"scotch bonnet\", \"vegetable oil\", \"seasoning cubes\"], \"cook_time_minutes\": 35, \"prep_time_minutes\": 15, \"missing_ingredients\": [\"salt\", \"thyme\"]}, {\"name\": \"Nigerian Tomato Stew\", \"servings\": 4, \"difficulty\": \"easy\", \"description\": \"A flavorful Nigerian stew made with tomatoes, onions, and spices, known for its tangy and slightly sweet taste profile.\", \"instructions\": [\"Heat 2 tablespoons of vegetable oil in a large pot over medium heat for 2 minutes\", \"Add 1 large onion, chopped, and sauté for 5 minutes\", \"Add 2 large tomatoes, chopped, and 1 scotch bonnet pepper, chopped, to the pot and stir well to combine\"], \"match_percentage\": 80, \"used_ingredients\": [\"tomatoes\", \"onions\", \"scotch bonnet\", \"vegetable oil\", \"seasoning cubes\"], \"cook_time_minutes\": 25, \"prep_time_minutes\": 10, \"missing_ingredients\": [\"salt\", \"meat or fish\"]}]}','2026-06-14 17:52:09'),('04462235-6aff-4aaa-adfa-75ad203c26de','[\"pasta\", \"tomatoes\", \"garlic\", \"onions\", \"olive oil\", \"cheese\", \"basil\", \"salt\", \"pepper\"]','italian',30,'{\"recipes\": [{\"name\": \"Spaghetti Aglio e Olio\", \"servings\": 4, \"difficulty\": \"easy\", \"description\": \"A classic Italian dish originating from Naples, known for its simplicity and bold flavors, with a taste profile that is both spicy and savory.\", \"instructions\": [\"Step 1: Bring a large pot of salted water to a boil, then add 1 cup of pasta and cook for 8-10 minutes on high heat, or until the pasta is al dente and has a slightly firm texture in the center, stirring occasionally to prevent sticking.\", \"Step 2: While the pasta is cooking, heat 1/4 cup of olive oil in a large skillet over medium heat for 2-3 minutes, or until it reaches a temperature of 180°F and starts to shimmer, then add 3 cloves of minced garlic and fry for 4-5 minutes on medium heat, or until the garlic turns golden brown and has a nutty aroma, stirring constantly to prevent burning.\", \"Step 3: Remove the garlic from the heat and let it cool for 1 minute, or until it stops sizzling and the aroma has dissipated, then stir in 1/2 cup of grated cheese and 1/4 cup of chopped fresh basil, and cook for an additional 1-2 minutes on low heat, or until the cheese has melted and the basil has wilted, stirring constantly to combine.\", \"Step 4: Drain the cooked pasta and add it to the skillet with the garlic and cheese mixture, tossing everything together for 2-3 minutes on low heat, or until the pasta is well coated with the sauce and has a creamy texture, stirring constantly to combine.\", \"Step 5: Season the pasta with salt and pepper to taste, or until the flavors are balanced and the pasta has a savory flavor profile, then cook for an additional 1 minute on low heat, or until the flavors have melded together, stirring constantly to combine.\", \"Step 6: Serve the spaghetti hot, garnished with additional basil and cheese if desired, and enjoy the bold flavors and satisfying texture of this classic Italian dish.\"], \"match_percentage\": 100, \"used_ingredients\": [\"pasta\", \"garlic\", \"olive oil\", \"cheese\", \"salt\", \"pepper\"], \"cook_time_minutes\": 15, \"prep_time_minutes\": 10, \"missing_ingredients\": []}, {\"name\": \"Tomato and Basil Pasta\", \"servings\": 4, \"difficulty\": \"easy\", \"description\": \"A simple and flavorful Italian dish that combines the sweetness of tomatoes with the brightness of basil, creating a taste profile that is both refreshing and savory.\", \"instructions\": [\"Step 1: Bring a large pot of salted water to a boil, then add 1 cup of pasta and cook for 8-10 minutes on high heat, or until the pasta is al dente and has a slightly firm texture in the center, stirring occasionally to prevent sticking.\", \"Step 2: While the pasta is cooking, heat 1/4 cup of olive oil in a large skillet over medium heat for 2-3 minutes, or until it reaches a temperature of 180°F and starts to shimmer, then add 2 cups of diced tomatoes and cook for 5-7 minutes on medium heat, or until the tomatoes start to release their juices and have a soft and tender texture, stirring occasionally to prevent burning.\", \"Step 3: Add 1/4 cup of chopped fresh basil to the skillet with the tomatoes and cook for an additional 1-2 minutes on low heat, or until the basil has wilted and the flavors have combined, stirring constantly to combine.\", \"Step 4: Stir in 1/2 cup of grated cheese and cook for an additional 1-2 minutes on low heat, or until the cheese has melted and the sauce has a creamy texture, stirring constantly to combine.\", \"Step 5: Drain the cooked pasta and add it to the skillet with the tomato and basil mixture, tossing everything together for 2-3 minutes on low heat, or until the pasta is well coated with the sauce and has a creamy texture, stirring constantly to combine.\", \"Step 6: Season the pasta with salt and pepper to taste, or until the flavors are balanced and the pasta has a savory flavor profile, then serve hot and enjoy the fresh and flavorful taste of this Italian dish.\"], \"match_percentage\": 100, \"used_ingredients\": [\"pasta\", \"tomatoes\", \"basil\", \"olive oil\", \"cheese\", \"salt\", \"pepper\"], \"cook_time_minutes\": 15, \"prep_time_minutes\": 10, \"missing_ingredients\": []}, {\"name\": \"Cheesy Pasta Bake\", \"servings\": 4, \"difficulty\": \"easy\", \"description\": \"A comforting and satisfying Italian-inspired dish that combines the richness of cheese with the heartiness of pasta, creating a taste profile that is both creamy and savory.\", \"instructions\": [\"Step 1: Preheat the oven to 375°F (190°C), then cook 1 cup of pasta according to the package instructions for 8-10 minutes on high heat, or until the pasta is al dente and has a slightly firm texture in the center, stirring occasionally to prevent sticking.\", \"Step 2: While the pasta is cooking, heat 1/4 cup of olive oil in a large skillet over medium heat for 2-3 minutes, or until it reaches a temperature of 180°F and starts to shimmer, then add 2 cups of diced tomatoes and cook for 5-7 minutes on medium heat, or until the tomatoes start to release their juices and have a soft and tender texture, stirring occasionally to prevent burning.\", \"Step 3: Stir in 1/2 cup of grated cheese and cook for an additional 1-2 minutes on low heat, or until the cheese has melted and the sauce has a creamy texture, stirring constantly to combine.\", \"Step 4: In a large bowl, combine the cooked pasta, tomato and cheese mixture, and 1/4 cup of chopped fresh basil, tossing everything together until the pasta is well coated with the sauce and has a creamy texture, stirring constantly to combine.\", \"Step 5: Transfer the pasta mixture to a baking dish and top with 1/2 cup of sliced cheese, then bake in the preheated oven for 10-12 minutes, or until the cheese is melted and bubbly, and the pasta is heated through, stirring occasionally to prevent burning.\"], \"match_percentage\": 100, \"used_ingredients\": [\"pasta\", \"cheese\", \"tomatoes\", \"olive oil\", \"salt\", \"pepper\"], \"cook_time_minutes\": 15, \"prep_time_minutes\": 10, \"missing_ingredients\": []}]}','2026-06-14 17:55:56'),('0cc94b19-f477-4f87-a6d7-c9c770b70a1b','[\"palm fruit\", \"fish\", \"crayfish\", \"scotch bonnet peppers\", \"onions\", \"assorted meat\"]','igbo',90,'{\"almost_there\": [{\"name\": \"Banga Stew\", \"tips\": \"The key difference between Banga Soup and Banga Stew is the reduction time — cook the stew version longer uncovered to achieve a thicker consistency that coats rice or yam well rather than the more liquid soup form.\", \"servings\": 5, \"difficulty\": \"hard\", \"description\": \"Banga Stew is a thick, deeply flavoured Igbo stew made from concentrated palm fruit extract, prepared similarly to Banga Soup but cooked down to a thicker consistency more like a stew than a soup. It is rich, nutty, and aromatic, traditionally seasoned with banga spices, and served with white rice, boiled yam, or plantain.\", \"instructions\": [\"Step 1: If using fresh palm fruit, boil for 20 to 30 minutes until soft, then pound to separate pulp from nuts and squeeze with warm water to extract the thick orange juice. Strain through a sieve to remove fibres. If using canned concentrate, dilute according to package instructions.\", \"Step 2: Pour the palm fruit extract into a pot and bring to a boil on high heat, then reduce to medium heat and simmer for 15 to 20 minutes until the oil begins to separate and rise to the surface.\", \"Step 3: Season the assorted meat with onions, seasoning cubes, and salt. Cook separately on medium heat for 30 minutes until tender. Add the cooked meat and stock to the palm fruit base.\", \"Step 4: Add the banga spice mix to the pot and simmer for 15 minutes to allow the spices to infuse fully into the base.\", \"Step 5: Add dried fish, ground crayfish, sliced scotch bonnet peppers, and seasoning cubes. Stir well and continue cooking on medium heat, allowing the liquid to reduce and thicken for 20 to 25 minutes — unlike Banga Soup this should reduce further into a thicker stew-like consistency.\", \"Step 6: Add the fresh fish pieces and cook gently for 8 to 10 minutes until just cooked through, stirring carefully to avoid breaking the fish apart.\", \"Step 7: Continue simmering uncovered for an additional 10 minutes, stirring occasionally, until the stew has thickened noticeably and the oil is clearly visible on the surface.\", \"Step 8: Remove the oburunbebe stick before serving. Taste and adjust seasoning. Serve hot with white rice, boiled yam, or plantain.\"], \"match_percentage\": 63.6, \"used_ingredients\": [\"fresh palm fruit (or canned banga concentrate)\", \"assorted meat (beef, tripe)\", \"dried fish\", \"fresh fish\", \"onions\", \"scotch bonnet peppers\", \"crayfish\"], \"cook_time_minutes\": 80, \"prep_time_minutes\": 30, \"missing_ingredients\": [\"banga spice mix (oburunbebe stick, dried bitter leaf)\", \"seasoning cubes\", \"salt\", \"water\"]}, {\"name\": \"Efo Riro\", \"tips\": \"The most important step is frying the pepper base completely dry until the oil floats on top before adding any meat or stock. This is what separates a rich deeply flavoured Efo Riro from a watery one. Also add the vegetables at the very last minute and cook for 2 minutes only — overcooked vegetables will turn dark and lose their flavour.\", \"servings\": 6, \"difficulty\": \"medium\", \"description\": \"Efo Riro is a rich Yoruba vegetable soup made with tatashe and ata rodo as the pepper base, assorted meats, and leafy green vegetables. The name means stirred leafy vegetable in Yoruba. It is one of the most flavourful Nigerian soups with a vibrant green and red colour from the vegetables and pepper base. It is served with amala, eba, pounded yam, or rice.\", \"instructions\": [\"Step 1: Wash and season assorted meat, pomo, and stockfish with onions, seasoning cubes, and salt. Cook on medium heat for 20 to 30 minutes until very tender. Set aside with the stock.\", \"Step 2: Blend tatashe and scotch bonnet peppers together into a smooth paste. Do not add water — the peppers have enough natural liquid. Set aside.\", \"Step 3: Wash the efo tete or spinach thoroughly, shred into medium sized pieces by hand, and set aside in a colander to drain excess water.\", \"Step 4: Heat palm oil in a large pot on medium-high heat for 2 minutes. Slice onions and fry in the palm oil for 3 minutes until golden and fragrant.\", \"Step 5: Add the blended tatashe and scotch bonnet pepper mixture to the pot. It will sizzle loudly in the hot oil — this is correct. Fry on high heat for 10 to 20 minutes stirring every 3 minutes until all the water has completely evaporated, the oil floats on top, and the pepper sauce has darkened and thickened. This step gives Efo Riro its deep rich flavour.\", \"Step 6: Add iru (locust beans) and ground crayfish and stir into the pepper sauce. Fry for 2 more minutes until the iru is fragrant.\", \"Step 7: Add the cooked assorted meat, stockfish, dried fish, and a ladle of the meat stock. Stir everything together and cook on medium heat for 10 minutes until the meat is well coated in the sauce.\", \"Step 8: Add the shredded efo tete or spinach to the pot and stir into the sauce. Cook for exactly 2 minutes only on medium heat — the vegetables should wilt into the soup but remain bright green and not soggy. Taste, adjust seasoning, and remove from heat immediately. Serve with amala, eba, or pounded yam.\"], \"match_percentage\": 50.0, \"used_ingredients\": [\"scotch bonnet peppers (ata rodo)\", \"onions\", \"assorted meat (beef, tripe, shaki, pomo)\", \"stockfish\", \"dried fish\", \"crayfish\"], \"cook_time_minutes\": 75, \"prep_time_minutes\": 25, \"missing_ingredients\": [\"vgetables African spinach or ugwu\", \"tatashe (red bell pepper)\", \"palm oil\", \"iru (locust beans)\", \"seasoning cubes\", \"salt\"]}], \"can_make_now\": [], \"needs_shopping\": [{\"name\": \"Ofe Owerri\", \"tips\": \"Use as many different types of meat and fish as you can for the most authentic version. The combination of ugu and uziza leaves together distinguishes this from Edikang Ikong.\", \"servings\": 6, \"difficulty\": \"hard\", \"description\": \"Ofe Owerri is a luxurious traditional Igbo vegetable soup from Owerri in Imo State, known for being loaded with multiple types of meat, fish, and a generous mix of vegetables, traditionally served at important ceremonies.\", \"instructions\": [\"Step 1: Wash and season all assorted meats and stockfish with onions, seasoning cubes, and salt. Cook on medium heat for 40 to 50 minutes until very tender. Set aside with the rich stock.\", \"Step 2: Peel cocoyam and boil until very soft, then pound until completely smooth to make the thickener.\", \"Step 3: Heat palm oil, add sliced onions and blended scotch bonnet peppers, fry for 15 minutes until oil floats on top.\", \"Step 4: Add all the cooked meats, stockfish, dried fish, periwinkle, ogiri, ground crayfish, and meat stock. Cook on medium heat for 15 minutes.\", \"Step 5: Add the pounded cocoyam thickener in small lumps and stir until dissolved.\", \"Step 6: Add the fresh fish pieces and cook gently for 8 minutes.\", \"Step 7: Add the shredded ugu and uziza leaves together and stir in. Cook for 3 to 5 minutes only.\", \"Step 8: Taste and adjust seasoning. Serve hot with pounded yam, fufu, or semolina.\"], \"match_percentage\": 46.7, \"used_ingredients\": [\"assorted meat (beef, tripe, shaki, cow leg)\", \"stockfish\", \"dried fish\", \"fresh fish\", \"crayfish\", \"onions\", \"scotch bonnet peppers\"], \"cook_time_minutes\": 85, \"prep_time_minutes\": 30, \"missing_ingredients\": [\"ugu leaves (fluted pumpkin)\", \"uziza leaves\", \"cocoyam (for thickening)\", \"palm oil\", \"periwinkle\", \"ogiri (fermented locust beans)\", \"seasoning cubes\", \"salt\"]}, {\"name\": \"Egusi Soup Yoruba Style\", \"tips\": \"The secret to Yoruba egusi is frying the egusi completely dry in palm oil before adding any liquid. Never add water or stock to the egusi while frying — it must fry and toast in the oil until golden. Also never add tomatoes to Yoruba egusi soup — that changes the flavour profile completely.\", \"servings\": 6, \"difficulty\": \"medium\", \"description\": \"Egusi Soup Yoruba style is a rich and hearty Nigerian soup made with ground melon seeds fried directly in palm oil before any liquid is added. Unlike Igbo style egusi which is added raw, Yoruba style fries the egusi first until golden and nutty giving it a deeper richer flavour. It is served with amala, eba, or pounded yam.\", \"instructions\": [\"Step 1: Wash and season assorted meat and stockfish with onions, seasoning cubes, and salt. Cook in a pot on medium heat for 15 to 20 minutes until tender. Set aside with the stock.\", \"Step 2: Blend scotch bonnet peppers, tatashe, and half the onions together into a smooth paste. Set aside.\", \"Step 3: Heat palm oil in a large pot on medium heat for 2 minutes until melted and hot but not bleached. Chop the remaining onions and fry in the palm oil for 3 minutes until soft and translucent.\", \"Step 4: Add the ground egusi to the palm oil and stir immediately to combine. Fry the egusi in the palm oil on medium heat for 8 to 10 minutes stirring constantly until the egusi turns golden, smells nutty, and pulls away from the sides of the pot. Do not add any liquid at this stage — dry frying is the key to Yoruba egusi.\", \"Step 5: Add the blended pepper mixture to the fried egusi and stir well to combine. Fry together for another 10 minutes on medium heat stirring every 2 minutes until the pepper is cooked and oil begins to float on the surface.\", \"Step 6: Add the cooked meat, stockfish, dried fish, meat stock, ground crayfish, iru, and seasoning cubes. Stir everything together and add a small amount of water if the soup is too thick. Cook on medium heat for 15 minutes until all the flavours come together.\", \"Step 7: Taste and adjust salt and seasoning. The soup should be rich, thick, and deeply flavoured at this point.\", \"Step 8: Add shredded spinach or efo tete and stir into the soup. Cook for exactly 2 minutes only — overcooking the vegetables will make them lose their colour and become soggy. Remove from heat and serve immediately with amala, eba, or pounded yam.\"], \"match_percentage\": 46.2, \"used_ingredients\": [\"assorted meat (beef, tripe, shaki)\", \"stockfish\", \"dried fish\", \"onions\", \"scotch bonnet peppers\", \"crayfish\"], \"cook_time_minutes\": 70, \"prep_time_minutes\": 20, \"missing_ingredients\": [\"ground egusi (melon seeds)\", \"palm oil\", \"tatashe (red bell pepper)\", \"iru (locust beans)\", \"spinach, efo tete or ugwu\", \"seasoning cubes\", \"salt\"]}, {\"name\": \"Ikokore\", \"tips\": \"Use water yam specifically not white yam or cocoyam. Do not rinse the grated yam before adding to the pot as the natural starch thickens the broth and holds the dumplings together.\", \"servings\": 4, \"difficulty\": \"medium\", \"description\": \"Ikokore is a traditional Ijebu Yoruba dish made from grated water yam cooked in a rich pepper soup or tomato base with assorted fish and seafood. The grated water yam forms thick irregular dumplings in the broth giving the dish its characteristic texture. It is a beloved dish in Ogun State and across Yorubaland.\", \"instructions\": [\"Step 1: Peel the water yam and grate on the coarse side of a grater into a bowl. Do not rinse the grated yam — the natural starch is needed to hold the dumplings together. Season the grated yam lightly with salt and set aside.\", \"Step 2: Blend scotch bonnet peppers, long chilli peppers, and onions together into a smooth paste.\", \"Step 3: Heat palm oil in a large pot on medium heat. Add iru and fry for 1 minute until fragrant. Add the blended pepper mixture and fry for 15 minutes until cooked and oil floats on top.\", \"Step 4: Add enough meat stock to the pot . Add ground crayfish, dried fish, smoked fish, assorted meat, seasoning cubes, and salt. Bring to a boil on high heat.\", \"Step 5: Using a tablespoon or your hand, scoop portions of the grated water yam and drop them one by one into the boiling broth. Do not stir immediately — allow the yam dumplings to set for 3 minutes before stirring gently.\", \"Step 6: Cook on medium heat for 15 to 20 minutes stirring gently occasionally until the yam dumplings are fully cooked and the broth has thickened, adjust seasoning, and serve hot.\"], \"match_percentage\": 46.2, \"used_ingredients\": [\"dried fish\", \"assorted meat\", \"smoked fish\", \"crayfish\", \"scotch bonnet peppers\", \"onions\"], \"cook_time_minutes\": 50, \"prep_time_minutes\": 25, \"missing_ingredients\": [\"water yam (isu ewura)\", \"palm oil\", \"long chilli peppers\", \"iru (locust beans)\", \"seasoning cubes\", \"salt\", \"water\"]}, {\"name\": \"Nigerian Pepper Soup\", \"tips\": \"The quality of your pepper soup spice mix makes or breaks this dish. Use freshly ground spices if possible — uda (country onion), ehuru (calabash nutmeg), and uziza seeds ground together give the most authentic flavour. Never cover the pot fully while cooking pepper soup — leave it slightly open so the broth reduces and concentrates.\", \"servings\": 4, \"difficulty\": \"easy\", \"description\": \"Nigerian Pepper Soup is a light, intensely spiced broth made with meat or fish and a unique blend of pepper soup spices. It is served at every Nigerian gathering, used as a remedy for colds and fever, and eaten as a starter or main dish. The broth is thin but deeply flavoured with a distinctive warming heat that comes from the special pepper soup spice blend.\", \"instructions\": [\"Step 1: Wash the meat thoroughly and cut into medium sized pieces. Season with onions, seasoning cubes, and salt. Do not add water yet — allow the meat to cook in its own juices first.\", \"Step 2: Place the seasoned meat in a pot on medium heat and cook dry for 10 minutes stirring occasionally until the meat releases its juices and begins to brown slightly on the outside.\", \"Step 3: Add enough water to cover the meat completely. Bring to a boil on high heat then reduce to medium heat. Cook for 25 to 30 minutes for goat meat or 15 minutes for chicken until the meat is tender but not falling off the bone.\", \"Step 4: Add the pepper soup spice mix, ground crayfish, and blended or roughly crushed scotch bonnet peppers. Stir well and taste — the broth should be well seasoned and spicy at this point. Add more seasoning cubes and salt if needed.\", \"Step 5: Cook on medium heat for another 15 minutes until the spices have fully infused into the broth and the liquid has reduced slightly. The broth should be a light golden brown colour and smell intensely aromatic.\", \"Step 6: Tear utazi leaves into small pieces and add to the pot — utazi adds a slight bitterness that balances the heat. Add uziza leaves whole or roughly torn. Cook for 3 minutes only.\", \"Step 7: Taste one final time and adjust salt and pepper. The pepper soup should be very hot and spicy, lightly bitter from the utazi, and deeply aromatic from the spice blend. Serve hot in deep bowls with sliced onions on top and agidi or white rice on the side.\"], \"match_percentage\": 40.0, \"used_ingredients\": [\"goat meat or chicken or catfish\", \"scotch bonnet peppers\", \"onions\", \"crayfish\"], \"cook_time_minutes\": 55, \"prep_time_minutes\": 15, \"missing_ingredients\": [\"pepper soup spice mix\", \"uziza leaves\", \"utazi leaves\", \"seasoning cubes\", \"salt\", \"water\"]}, {\"name\": \"Moi Moi\", \"tips\": \"The food processor peeling method is a game changer — it cuts prep time from 30 minutes to 5 minutes. The two most important steps are removing every single bean skin and whisking the paste vigorously to aerate it before adding seasoning. Skipping either step will result in dense heavy Moi Moi. Always fill containers only three quarters full as the paste expands during steaming.\", \"servings\": 8, \"difficulty\": \"medium\", \"description\": \"Moi Moi is a traditional Nigerian steamed bean pudding made from peeled beans blended into a smooth paste. It is a beloved dish across all Nigerian tribes and is served at parties, as a side dish with rice or ogi, or eaten alone as a complete meal. The texture should be firm yet soft and moist inside with a rich savoury flavour.\", \"instructions\": [\"Step 1: There are two ways to peel the beans. Traditional method: Pour beans into a bowl and soak in cold water for 30 minutes until the skins begin to loosen and soften, then rub vigorously between both palms under running water until all skins float off. Quick method: Pour dry beans into a food processor with some water and pulse for 30 to 45 seconds — the food processor will crack and loosen the skins without grinding the beans. Pour the pulsed beans into a large bowl of water, the skins will float to the top — skim them off and drain. Repeat until all skins are removed. The quick method takes 5 minutes instead of 30.\", \"Step 2: Rinse the peeled beans thoroughly in clean water two to three times to remove any remaining skin fragments. The beans should be completely white with no dark skin remaining — any leftover skin will make the Moi Moi rough and bitter.\", \"Step 3: Place the peeled beans directly into the blender together with the scotch bonnet peppers, red bell pepper, onions, one raw egg, and a very small amount of water — just enough to get the blender moving. Blend everything together on high speed for 3 minutes until the paste is completely smooth with absolutely no grainy texture. Blending the peppers and egg together with the beans at this stage gives the Moi Moi its full flavour and colour from the inside.\", \"Step 4: Pour the blended paste into a large bowl. Add seasoning cubes, vegetable oil, and salt. Mix everything together thoroughly until well combined. Taste and adjust seasoning — it should be well seasoned and slightly peppery.\", \"Step 5: Using a wooden spoon or electric hand mixer, whisk the paste vigorously for 5 minutes until it becomes fluffy, lighter in colour, and increases slightly in volume. This aerates the paste and gives Moi Moi its soft moist texture when steamed.\", \"Step 6: Break the mackerel fish into medium sized chunks and slice your boiled eggs and set aside. Grease foil containers or moi moi leaves generously with vegetable oil on the inside so the moi moi does not stick.\", \"Step 7: Pour the bean paste mixture into each container filling only three quarters full. Drop pieces of fish directly into the paste in each container alongside the sliced eggs  — the fish sits inside the moi moi not on top. Press down lightly so the fish is submerged in the paste.\", \"Step 8: Seal each foil container tightly by folding the edges over securely. No steam should be able to escape during cooking.\", \"Step 9: Place a trivet or folded foil at the bottom of a large pot to prevent direct heat contact. Arrange the sealed moi moi containers in the pot and add water to reach halfway up the sides of the containers.\", \"Step 10: Cover the pot tightly and steam on medium heat for 45 to 60 minutes. Check water level every 15 minutes and add more hot water if needed — never let the pot run dry. Moi Moi is ready when it feels firm when pressed gently and pulls away cleanly from the container when opened.\"], \"match_percentage\": 36.4, \"used_ingredients\": [\"onions\", \"scotch bonnet peppers\", \"crayfish\", \"fish (preferably mackerel fish)\"], \"cook_time_minutes\": 60, \"prep_time_minutes\": 40, \"missing_ingredients\": [\"beans\", \"long chilli pepper (shombo)\", \"vegetable oil\", \"seasoning cubes\", \"salt\", \"eggs\", \"water\"]}, {\"name\": \"Ayamase (Ofada Stew)\", \"tips\": \"Bleaching the palm oil is absolutely non-negotiable for authentic Ayamase. Only use green peppers and unripe tatashe — no red peppers at all. The more assorted meats you use the richer and more authentic the stew will be.\", \"servings\": 6, \"difficulty\": \"hard\", \"description\": \"Ayamase also known as Ofada Stew or Designer Stew is a rich and intensely flavoured Yoruba stew made exclusively with green peppers and unripe tatashe giving it its distinctive green colour. It is traditionally served with Ofada rice and the stew is made with bleached palm oil and loaded with assorted meats making it one of the most indulgent Nigerian dishes.\", \"instructions\": [\"Step 1: Wash and season all assorted meats with onions, seasoning cubes, ginger garlic paste and salt. Cook in a pot on medium heat for 25 to 35 minutes until very tender. Fry the cooked meats in a small amount of oil until lightly browned on the outside for extra flavour. Set aside with the stock.\", \"Step 2: Blend green bell peppers, unripe green tatashe, green scotch bonnet peppers, and onions together into a coarse paste — do not blend completely smooth, leave some texture. The stew must use only green peppers and unripe tatashe — never red peppers or ripe tatashe as this completely changes the dish.\", \"Step 3: Bleach the palm oil by heating it in a pot on high heat with the lid on for 10 to 15 minutes until the oil turns from orange-red to a pale golden yellow colour and begins to smoke lightly. Remove from heat and allow to cool slightly. Bleached palm oil is essential for authentic Ayamase.\", \"Step 4: Return the bleached palm oil to medium heat. Add sliced onions with some ginger garlic paste and fry for 3 minutes until soft and slightly golden.\", \"Step 5: Pour the blended green pepper mixture into the bleached palm oil. It will sizzle vigorously stir immediately. Fry on high heat for 15 to 20 minutes stirring every 3 to 4 minutes until all the water has completely evaporated, the oil floats on top, and the pepper sauce is cooked down and thick.\", \"Step 6: Add iru (locust beans) and ground crayfish to the cooked pepper base and stir well. Fry for 3 more minutes until the iru is fragrant and well incorporated.\", \"Step 7: Add all the assorted meats and a ladle of the meat stock. Stir everything together to coat the meat in the green pepper sauce. Cook on medium heat for 10 minutes until the meat is well flavoured and the stew is thick and rich.\", \"Step 8: Taste and adjust seasoning. The finished Ayamase should be dark olive green, thick, intensely flavoured, and very rich with assorted meats. Serve with Ofada rice.\"], \"match_percentage\": 36.4, \"used_ingredients\": [\"green scotch bonnet peppers\", \"onions\", \"assorted meat (beef, tripe, shaki, pomo, liver)\", \"crayfish\"], \"cook_time_minutes\": 90, \"prep_time_minutes\": 25, \"missing_ingredients\": [\"green bell peppers\", \"unripe tatashe (green tatashe)\", \"palm oil\", \"iru (locust beans)\", \"seasoning cubes\", \"ginger and garlic paste\", \"salt\"]}, {\"name\": \"Asaro (Yam Porridge)\", \"tips\": \"Gentle stirring lets some yam break down to thicken the sauce naturally without becoming completely mashed.\", \"servings\": 4, \"difficulty\": \"easy\", \"description\": \"Asaro is a beloved traditional Yoruba yam porridge made by cooking yam chunks directly in a rich tomato and pepper sauce until the yam softens and thickens the entire dish into a hearty one-pot meal.\", \"instructions\": [\"Step 1: Peel the yam and cut into medium sized chunks. Wash thoroughly.\", \"Step 2: Blend onions, tatashe, and scotch bonnet peppers together into a smooth paste.\", \"Step 3: Place the yam chunks in a pot with the blended pepper mixture, sliced onions, palm oil, and enough water to just cover the yam.\", \"Step 4: Bring to a boil then reduce to medium heat. Cook for 20 to 25 minutes, stirring occasionally, until the yam softens and breaks down at the edges.\", \"Step 5: Add ground crayfish, flaked fish, seasoning cubes, and salt. Stir gently.\", \"Step 6: Continue cooking on medium-low heat for 8 to 10 minutes until thick and stew-like.\", \"Step 7: Taste and adjust seasoning. Serve hot on its own.\"], \"match_percentage\": 36.4, \"used_ingredients\": [\"scotch bonnet peppers\", \"onions\", \"crayfish\", \"smoked fish or dried fish\"], \"cook_time_minutes\": 40, \"prep_time_minutes\": 15, \"missing_ingredients\": [\"yam (white yam)\", \"tomatoes\", \"tatashe (red bell pepper)\", \"palm oil\", \"seasoning cubes\", \"salt\", \"water\"]}, {\"name\": \"Abacha\", \"tips\": \"Always soak in cold water not hot. Potash is essential for emulsifying the palm oil into the dressing.\", \"servings\": 4, \"difficulty\": \"medium\", \"description\": \"Abacha is a traditional Igbo cold salad made from dried shredded cassava rehydrated and tossed in an emulsified palm oil and potash dressing with ugba, utazi leaves, garden eggs, crayfish, and assorted proteins.\", \"instructions\": [\"Step 1: Soak the dried abacha in cold water for 10 to 15 minutes until softened. Drain thoroughly.\", \"Step 2: Dissolve potash in 3 tablespoons of water and strain through a fine sieve.\", \"Step 3: Pour palm oil into a bowl. Add the potash solution gradually while stirring vigorously until emulsified and bright yellow.\", \"Step 4: Add ground crayfish, sliced scotch bonnet peppers, sliced onions, seasoning cubes, and salt to the emulsion.\", \"Step 5: Add the drained abacha and toss thoroughly until coated.\", \"Step 6: Add ugba, sliced garden eggs, shredded utazi, flaked fish, and sliced ponmo. Toss together gently.\", \"Step 7: Taste and adjust seasoning.\", \"Step 8: Garnish with utazi and onion rings. Serve at room temperature.\"], \"match_percentage\": 30.8, \"used_ingredients\": [\"crayfish\", \"onions\", \"scotch bonnet peppers\", \"dried fish or stockfish\"], \"cook_time_minutes\": 0, \"prep_time_minutes\": 20, \"missing_ingredients\": [\"abacha (dried shredded cassava)\", \"ugba (oil bean seeds)\", \"palm oil\", \"potash (kaun)\", \"utazi leaves\", \"garden eggs\", \"seasoning cubes\", \"salt\", \"ponmo (cow skin)\"]}, {\"name\": \"Akara\", \"tips\": \"Whisking the bean paste until very fluffy is the secret to light soft akara — never skip this step. Also make sure the oil is very hot before adding the paste otherwise the akara will absorb too much oil and become greasy. Wet your spoon with oil before scooping each portion to help the paste slide off cleanly into the oil.\", \"servings\": 4, \"difficulty\": \"medium\", \"description\": \"Akara is a traditional Yoruba deep fried bean cake made from peeled black eyed beans blended into a smooth aerated paste and fried in hot oil until crispy on the outside and soft inside. It is a quintessential Nigerian breakfast food sold by roadside vendors across the country and best eaten hot with ogi (pap) or bread.\", \"instructions\": [\"Step 1: Peel the beans using one of two methods. Traditional method: Soak beans in cold water for 30 minutes then rub between palms under running water until all skins float off and are drained away. Quick method: Pulse beans and water  in a food processor for 30 seconds to crack and loosen skins, pour into a bowl of water, skim off floating skins, and drain. Rinse peeled beans two to three times in clean water.\", \"Step 2: Place the peeled beans alongside the peppers and onions in a blender with a very small amount of water — just enough to move the blender. Blend on high speed for 3 minutes until the paste is completely smooth and thick. The paste must be thick not watery — too much water will make flat oily akara.\", \"Step 3: Pour the blended bean paste into a large bowl. Using a wooden spoon or electric hand mixer whisk the paste vigorously for 5 to 7 minutes until it becomes very fluffy, lighter in colour, and almost doubles in volume. This is the most important step — the air you whisk in is what makes akara light and fluffy inside.\", \"Step 4: Add some salt and seasoning cubes to the whisked paste. Fold gently into the paste without deflating it. Taste and adjust seasoning.\", \"Step 5: Pour enough vegetable oil into a deep wide pan to allow the akara to float — at least 3 inches deep. Heat on medium-high heat for 2 to 3 minutes until hot. Test the oil by dropping a tiny bit of paste in — it should rise immediately to the surface and sizzle vigorously. If it sinks the oil is not hot enough.\", \"Step 6: Wet your tablespoon with oil and scoop portions of the paste into the hot oil one at a time. Do not overcrowd the pan — leave space between each akara so they cook evenly and stay round.\", \"Step 7: Fry on medium heat for 3 to 4 minutes until the bottom is deep golden brown, then flip carefully with a slotted spoon or skewer and fry the other side for 2 to 3 minutes until evenly golden brown and crispy all over.\", \"Step 8: Remove with a slotted spoon and drain on paper towels to absorb excess oil. Serve immediately while hot and crispy alongside ogi (pap) or as a breakfast snack.\"], \"match_percentage\": 28.6, \"used_ingredients\": [\"onions\", \"scotch bonnet peppers\"], \"cook_time_minutes\": 20, \"prep_time_minutes\": 30, \"missing_ingredients\": [\"black eyed beans\", \"long chilli peppers(shombo)\", \"seasoning cubes\", \"salt\", \"vegetable oil for deep frying\"]}, {\"name\": \"Ewa Agoyin\", \"tips\": \"The two secrets to authentic Ewa Agoyin are cooking the beans with a lot of onions until completely mashable with no whole beans remaining, and making the Agoyin stew with only dried peppers not fresh ones. Fresh peppers will not give the deep dark colour and concentrated flavour that makes Agoyin stew unique. The stew must be dark, dry, and almost burnt looking — that is correct.\", \"servings\": 4, \"difficulty\": \"medium\", \"description\": \"Ewa Agoyin is a popular Yoruba street food originally brought to Nigeria by Beninese traders, consisting of soft completely mashed honey beans or black eyed beans served with a deeply dark and spicy Agoyin stew made from dried red peppers and palm oil. It is a beloved Lagos breakfast food sold by roadside vendors and eaten with agege bread.\", \"instructions\": [\"Step 1: Wash the beans thoroughly then cover the beans with fresh water and cook on high heat until boiling, then reduce to medium heat. Cook for 45 to 60 minutes until the beans are extremely soft — they should mash completely between your fingers with no resistance. Add more water as needed during cooking to prevent burning.\", \"Step 2: Once the beans are very soft, use a wooden spoon or potato masher to mash them completely in the pot until no whole beans remain. The consistency should be thick and porridge-like. Season with salt, stir well, and set aside.\", \"Step 4: While the beans cook prepare the Agoyin stew. Rehydrate the dried red peppers and dried chilli peppers by soaking in hot water for 20 minutes until soft. Drain and blend alongside some onions and ginger into a rough paste — not completely smooth, leave some texture.\", \"Step 5: Heat palm oil in a separate pot on medium heat until hot. Slice onions into thin rings and fry in the palm oil for 10 minutes on medium-low heat, stirring constantly until the onions are very dark brown and almost caramelised — this dark onion is essential to the Agoyin stew flavour.\", \"Step 6: Add the blended dried pepper mixture to the dark onions and palm oil. Stir well and fry on medium heat for 20 to 25 minutes stirring every 3 minutes until all moisture evaporates, the stew becomes very dark, thick, and dry, and the oil floats on top. The stew should be almost black in colour — this is correct.\", \"Step 7: Add seasoning cubes and salt to the stew. Stir well and cook for 5 more minutes. The finished Agoyin stew should be very dark, very dry, very spicy, and intensely flavoured.\", \"Step 8: Serve the mashed beans in a bowl and pour the dark Agoyin stew generously on top. Eat with agege bread, fried plantain, or on its own.\"], \"match_percentage\": 22.2, \"used_ingredients\": [\"onions\", \"crayfish\"], \"cook_time_minutes\": 90, \"prep_time_minutes\": 20, \"missing_ingredients\": [\"beans\", \"dried red peppers (tatashe)\", \"dried long chilli bonnet peppers(shombo)\", \"palm oil\", \"seasoning cubes\", \"salt\", \"water\"]}, {\"name\": \"Asun\", \"tips\": \"Grilling or smoking the goat meat after boiling is non-negotiable for authentic Asun — without the charred smoky exterior the dish is just peppered goat meat not Asun. Use goat meat with the skin on for the best texture and flavour. The pepper sauce should have chunky sliced peppers not a blended smooth sauce.\", \"servings\": 4, \"difficulty\": \"medium\", \"description\": \"Asun is a popular Yoruba delicacy of smoked or roasted goat meat cut into small pieces and tossed in a fiery pepper and onion sauce. It originates from Ondo State in Yorubaland and is now one of the most popular Nigerian party small chops and appetisers served across the country. The goat meat is first smoked or roasted to give it a distinctive charred flavour before being peppered.\", \"instructions\": [\"Step 1: Wash the goat meat thoroughly — authentic Asun uses goat meat with the skin on as the skin adds texture and flavour. Cut into medium sized chunks. Season with seasoning cubes, curry powder, thyme, ginger garlic paste and salt.\", \"Step 2: Cook the seasoned goat meat in a pot with a small amount of water on medium heat for 20 to 25 minutes until tender but not falling apart.\", \"Step 3: Remove the cooked goat meat and place directly on a grill, open flame, or in a very hot oven at 220 degrees Celsius. Grill or roast for 15 to 20 minutes turning occasionally until the outside is charred and smoky and the skin is slightly crispy. The charring is essential for authentic Asun flavour.\", \"Step 4: Remove from the grill and cut into smaller bite sized pieces while still hot. Set aside.\", \"Step 5: Slice scotch bonnet peppers, green bell pepper, red bell pepper, and onions into thin strips. The peppers should be sliced not blended, a food processor can be used as well — the chunky pepper pieces are characteristic of Asun.\", \"Step 6: Heat vegetable oil in a wide pan on medium heat. Add the sliced onions and fry for 2 minutes until slightly softened.\", \"Step 7: Add all the sliced peppers to the pan and stir fry on high heat for 3 to 4 minutes — the peppers should be cooked but still have a slight crunch. Do not overcook the peppers into mush.\", \"Step 8: Add the grilled goat meat pieces to the pan and toss vigorously with the peppers for 3 minutes on high heat until the meat is well coated in the pepper mixture and everything is sizzling hot. Taste and adjust seasoning. Serve immediately as a party appetiser or small chop.\"], \"match_percentage\": 18.2, \"used_ingredients\": [\"scotch bonnet peppers\", \"onions\"], \"cook_time_minutes\": 60, \"prep_time_minutes\": 20, \"missing_ingredients\": [\"goat meat (skin on)\", \"green bell pepper\", \"red bell pepper (tatashe)\", \"vegetable oil\", \"seasoning cubes\", \"curry powder\", \"thyme\", \"salt\", \"ginger garlic paste\"]}, {\"name\": \"Nigerian Jollof Rice\", \"tips\": \"The secret to party jollof is double covering with foil and lid to trap steam, and finishing on high heat for the smoky bottom layer. Never use fresh tomatoes alone — always add tomato paste for depth of colour and flavour.\", \"servings\": 6, \"difficulty\": \"medium\", \"description\": \"Nigerian Jollof Rice is one of the most beloved dishes in West Africa, known for its rich smoky tomato flavour and vibrant orange-red colour. It is a staple at every Nigerian party, celebration, and family gathering. The secret to authentic Jollof Rice is the smoky bottom layer called party jollof which develops from cooking on high heat at the end.\", \"instructions\": [\"Step 1: Blend tomatoes, red bell peppers, long chilli peppers, scotch bonnet, and onions together in a blender until completely smooth with no chunks remaining. Set aside.\", \"Step 2: Wash rice thoroughly in cold water at least 3 times until water runs clear.\", \"Step 3: Heat vegetable oil in a large heavy-bottomed stainless steel or aluminum pot over medium-high heat for 2 minutes. Slice some onions, ginger and garlic paste, curry, thyme, bay leaves  and fry in the oil for 3 minutes.\", \"Step 4: Add tomato paste to the pot and fry with the mix for 3 minutes on medium heat, stirring constantly until the paste darkens slightly from bright red to a deeper reddish brown.\", \"Step 5: Pour the blended pepper mixture with some paprika into the pot. It will sizzle loudly — this is correct. Add in some seasoning cubes and salt. Fry on medium high heat uncovered for 25-30 minutes stirring every 5 minutes until all the water has evaporated, the oil floats on top, and the sauce has darkened to a deep red color. This step is critical — do not rush it.\", \"Step 6: Stir well and taste the sauce should be slightly salty as it will season the rice\", \"Step 7: Add the rice to the pot and stir well to coat every grain with the tomato sauce. Fry on high for like 2 minutes. Then add in chicken stock and some water enough to just cover the rice\", \"Step 8: Cover the pot tightly with foil first then place the lid on top to seal in all the steam. Cook on medium heat for 20 minutes without lifting the lid.\", \"Step 9: After 20 minutes lift the lid and check — rice should be almost fully cooked and liquid mostly absorbed. Stir gently from bottom to top. Cover again and cook on very low heat for 10 more minutes.\", \"Step 10: For the authentic party jollof smoky bottom, add in some cooking butter and sliced onions turn heat to high for the last 3-5 minutes. You will hear a crackling sound from the bottom — this is correct. Remove from heat immediately and leave covered for 5 minutes before serving.\"], \"match_percentage\": 12.5, \"used_ingredients\": [\"scotch bonnet peppers (ata rodo)\", \"onions\"], \"cook_time_minutes\": 70, \"prep_time_minutes\": 20, \"missing_ingredients\": [\"long grain parboiled rice\", \"tomatoes\", \"red bell peppers (tatashe)\", \"long chilli peppers(shombo) \", \"vegetable oil\", \"tomato paste\", \"chicken stock\", \"seasoning cubes\", \"curry powder\", \"thyme\", \"bay leaves\", \"garlic powder\", \"salt\", \"paprika\"]}, {\"name\": \"Nigerian Fried Rice\", \"tips\": \"Always cook on high heat when frying the rice and vegetables together to prevent everything from steaming and becoming soggy instead of stir-fried.\", \"servings\": 6, \"difficulty\": \"medium\", \"description\": \"Nigerian Fried Rice is a colourful and flavourful party staple made with parboiled rice stir-fried with mixed vegetables, liver, and a distinct curry seasoning. Unlike Chinese fried rice, the Nigerian version has a unique orange-yellow hue from curry powder and is loaded with vegetables, making it one of the most popular dishes at Nigerian celebrations alongside Jollof Rice.\", \"instructions\": [\"Step 1: Wash the rice thoroughly until water runs clear then transfer into a seive till perfectly dry. Then into a pot, add some oil and fry the rice for about 5 minutes\", \"Step 2: Season the liver with salt and a little curry powder. Cook in a pot with a small amount of water for 8 to 10 minutes until just cooked through, then dice into small cubes.\", \"Step 3: Dice carrots and green beans into small uniform cubes for even cooking. Set aside along with the bell peppers.\", \"Step 4: Heat vegetable oil in a large wok or wide pan on high heat. Add minced garlic and ginger and stir fry for 30 seconds until fragrant but not browned.\", \"Step 5: Add diced onions and stir fry for 2 minutes until softened. Add the diced liver and shrimp and stir fry for 2 minutes.\", \"Step 6: Add the carrots, green beans, green peas, and bell peppers to the pan. Stir fry on high heat for 3 minutes until heated through but still slightly crisp.\", \"Step 7: Add the cooled parboiled rice to the pan along with curry powder, thyme, seasoning cubes, soy sauce, and salt. Stir fry vigorously on high heat for 5 to 7 minutes, tossing continuously, until the rice is evenly coated in the yellow curry colour and well combined with all the vegetables and protein. Taste and adjust seasoning, then serve hot.\"], \"match_percentage\": 6.7, \"used_ingredients\": [\"onions\"], \"cook_time_minutes\": 30, \"prep_time_minutes\": 30, \"missing_ingredients\": [\"long grain rice\", \"carrots\", \"green peas\", \"bell peppers(green, yellow, red)\", \"liver\", \"vegetable oil\", \"garlic\", \"ginger\", \"curry powder\", \"thyme\", \"seasoning cubes\", \"soy sauce\", \"salt\", \"chicken stock\"]}, {\"name\": \"Nigerian Coleslaw\", \"tips\": \"The combination of mayonnaise and salad cream together, rather than just mayonnaise alone, is what gives Nigerian coleslaw its distinctive tangy sweetness. Always shred the cabbage very finely for the best texture, and let the coleslaw rest in the refrigerator before serving for the best flavour.\", \"servings\": 6, \"difficulty\": \"easy\", \"description\": \"Nigerian Coleslaw is a creamy and slightly sweet shredded cabbage and carrot salad that is a staple side dish at Nigerian parties, often served alongside Jollof Rice and Fried Rice. It differs from Western coleslaw by typically including diced apples, raisins, and a generously sweetened mayonnaise dressing.\", \"instructions\": [\"Step 1: Wash the cabbage thoroughly and shred very finely using a sharp knife or food processor — the cabbage should be cut into thin uniform strips for the best texture.\", \"Step 2: Peel and grate or finely julienne the carrots into thin matchstick pieces, similar in size to the shredded cabbage.\", \"Step 3: In a large bowl combine the shredded cabbage, grated carrots and sweet corn. Toss together gently.\", \"Step 4: In a separate small bowl mix mayonnaise and salad cream together in roughly equal parts, adding sugar to taste for the characteristic Nigerian sweetness, along with a pinch of black pepper and salt.\", \"Step 5: Pour the dressing over the vegetable mixture and toss thoroughly until every piece is well coated in the creamy dressing.\", \"Step 6: Taste and adjust sweetness and seasoning — Nigerian coleslaw is typically sweeter than standard Western coleslaw.\", \"Step 7: Cover and refrigerate for at least 1 hour before serving to allow the flavours to meld and the cabbage to soften slightly. Serve cold alongside Jollof Rice or Fried Rice.\"], \"match_percentage\": 0.0, \"used_ingredients\": [], \"cook_time_minutes\": 0, \"prep_time_minutes\": 25, \"missing_ingredients\": [\"cabbage\", \"carrots\", \"sweet corn\", \"mayonnaise\", \"salad cream\", \"sugar\", \"black pepper\", \"salt\"]}]}','2026-06-18 15:14:07'),('27c1a661-c8fa-40fb-878c-6f9aba14e2c0','[\"rice\", \"tomato paste\", \"onions\", \"scotch bonnet peppers\", \"tatashe\", \"ginger garlic paste\"]','nigerian',NULL,'{\"almost_there\": [], \"can_make_now\": [], \"needs_shopping\": [{\"name\": \"Asun\", \"tips\": \"Grilling or smoking the goat meat after boiling is non-negotiable for authentic Asun — without the charred smoky exterior the dish is just peppered goat meat not Asun. Use goat meat with the skin on for the best texture and flavour. The pepper sauce should have chunky sliced peppers not a blended smooth sauce.\", \"servings\": 4, \"difficulty\": \"medium\", \"description\": \"Asun is a popular Yoruba delicacy of smoked or roasted goat meat cut into small pieces and tossed in a fiery pepper and onion sauce. It originates from Ondo State in Yorubaland and is now one of the most popular Nigerian party small chops and appetisers served across the country. The goat meat is first smoked or roasted to give it a distinctive charred flavour before being peppered.\", \"instructions\": [\"Step 1: Wash the goat meat thoroughly — authentic Asun uses goat meat with the skin on as the skin adds texture and flavour. Cut into medium sized chunks. Season with seasoning cubes, curry powder, thyme, ginger garlic paste and salt.\", \"Step 2: Cook the seasoned goat meat in a pot with a small amount of water on medium heat for 20 to 25 minutes until tender but not falling apart.\", \"Step 3: Remove the cooked goat meat and place directly on a grill, open flame, or in a very hot oven at 220 degrees Celsius. Grill or roast f